local LxBaseAdapter = require("LApp.adapter.LxBaseAdapter")
---@class LxLoaderAdapter:LxBaseAdapter
local LxLoaderAdapter = classX("LxLoaderAdapter", LxBaseAdapter)

local PJXGameMgr = PJXCenter.GameMgr

local ADAPTER_LOG_TAG = "LoaderAdapter"

local LOAD_MAX_PROGRESS = 0.95
local LOAD_MAX_PROGRESS_STEP1 = 0.7
local LOAD_MAX_PROGRESS_STEP2 = 0.25

local ELoadType = {
    InLoader = 0,  --- 正常模式， 会出loader条，进入loader场景， 进入loader场景后清理资源
    NoLoader = 1, --- 没有显著的loader界面模式，不会进入loader场景， 加载完成后清理资源
    NoLoaderWithoutRelease = 2 --- 没有显著的loader界面模式，不会进入loader场景， 不清理资源
}

local LoadSceneMode = UnityEngine.SceneManagement.LoadSceneMode

function LxLoaderAdapter:Initialize()
    LxBaseAdapter.Initialize(self)
    self._adapterName = LevelNames.Loader
    self._targetLevelName = nil

    ---@type LxBatchTask
    self._batchTask = nil
    ---@type LxPreloadTask
    self._preloadTask = nil

    self._isLoading = false

    self._nextFreeGCTime = nil
end

function LxLoaderAdapter:Dispose()
    if self._preloadTask then
        self._preloadTask:Dispose()
        self._preloadTask = nil
    end
    if self._batchTask then
        self._batchTask:StopBatchTask()
        self._batchTask = nil
    end
    LxBaseAdapter.Dispose(self)
end

---进入加载场景
function LxLoaderAdapter:OnEnterLevel(scene, loadMode)
    self:InternalStartLoad()
end

---退出加载场景
function LxLoaderAdapter:OnLeaveLevel(scene)

end

function LxLoaderAdapter:IsLoading()
    return self._isLoading
end

function LxLoaderAdapter:GetTargetLevelName()
    return self._targetLevelName
end

function LxLoaderAdapter:GetOldLevelName()
    return self._oldLevelName
end
