---region 场景加载处理
function LxLoaderAdapter:StartLoadLevel(levelName, oldLevelName, param)
    --FireEvent(EventNames.LEVEL_LOAD_START, self._curLevelName, oldLevelName)
    --
    LGameRunMode.SetRunMode(LGameRunMode.LOADING_SCENE)

    gLGame:SetGameTimeScale(1)
    gLGame:DoResumeGameTime()


    self._isLoading = true

    self._targetLevelName = levelName
    self._oldLevelName = oldLevelName

    param = param or {}

    self._loadType = ELoadType.InLoader
    local loadSceneMode = param.loadSceneMode or LoadSceneMode.Single
    self._loadSceneMode = loadSceneMode

    self._targetAdapter =  MgrCenter.AdapterMgr:GetAdapter(levelName)
    self._targetAdapter:OnWillEnterLevel()

    GF.CloseWndByName("UILoadsng")

    if not self._targetAdapter:IsUseLoader() then
        self._loadType = ELoadType.NoLoaderWithoutRelease
        MgrCenter.LevelMgr:OnLevelChanged(oldLevelName, levelName)
        self:InternalStartLoad()
        return
    end

    local bBlackEnding = param.waitBlack or false
    local clearBgWnd = param.clearBgWnd or false
    local bWaitVideo = param.waitVideo or false
    --local loadEndFunc = param.loadEndFunc or nil

    local loadedFunc = function()
        MgrCenter.LevelMgr:OnLevelChanged(oldLevelName, levelName)
        MgrCenter.LevelMgr:ExecuteLevelLoad(LevelNames.Loader, LoadSceneMode.Single)
    end

    local bHideLoadingBg = self._targetAdapter:IsHideLoadingBg()
    --GF.OpenUILoadsng("UILoadsng",{
    --    cb = loadedFunc,
    --    sceneName = levelName, rate = self._targetAdapter:GetScenePrepareRate(),
    --    waitVideo = bWaitVideo, blackEnd = bBlackEnding,
    --    hideBg = bHideLoadingBg , clearBgWnd = clearBgWnd
    --})
    param.cb = loadedFunc
    param.sceneName = levelName
    param.rate = self._targetAdapter:GetScenePrepareRate()
    param.waitVideo = bWaitVideo
    param.blackEnd = bBlackEnding
    param.hideBg = bHideLoadingBg
    param.clearBgWnd = clearBgWnd
    param.loadEndFunc = self._targetAdapter:GetSceneLoadEndFunc()
    param.hideProgress = self._targetAdapter:IsHideProgress()
    GF.OpenUILoadsng("UILoadsng", param)
end

function LxLoaderAdapter:GetBatchTask()
    local batchTask = self._batchTask
    if not batchTask then
        batchTask = require("LApp.component.task.LxBatchTask"):New()
        batchTask:Initialize()
        self._batchTask = batchTask
    end
    return batchTask
end

function LxLoaderAdapter:InternalStartLoad()
    if self._preloadTask then
        self._preloadTask:ClearResRequesters()
    end

    local batchTask = self:GetBatchTask()

    batchTask:InitBatchTask(self.OnBatchTaskText, self.OnBatchTaskProgress, self.OnLoadBeforeTaskOk, self)
    if self._loadType == ELoadType.NoLoader then
        batchTask:AddBatchTask("loadLevel", "loadLevel", self.LoadLevel, self)
    elseif self._loadType == ELoadType.NoLoaderWithoutRelease then
        batchTask:AddBatchTask("clearOpenPanel", "", self.ClearOpenPanel, self)
        batchTask:AddBatchTask("loadLevel", "loadLevel", self.LoadLevel, self)
    else
        batchTask:AddBatchTask("clearOpenPanel", "", self.ClearOpenPanel, self)
        batchTask:AddBatchTask("unload", "", self.UnloadUnusedAssets, self)
        batchTask:AddBatchTask("gc", "", self.DoGameGC, self)
        batchTask:AddBatchTask("preload", "preload", self.PreloadAssets, self)
        batchTask:AddBatchTask("preload2", "preload2", self.PreloadAssets2, self)
        batchTask:AddBatchTask("FrameDoSomeThing", "frameDoSomeThing", self.FrameDoSomeThing, self)
        batchTask:AddBatchTask("delaySometime", "", self.DelaySometime, self)
        batchTask:AddBatchTask("loadLevel", "loadLevel", self.LoadLevel, self)
    end
    batchTask:StartBatchTask()
end

function LxLoaderAdapter:InternalFinishLoad()
    self:StopAllTimer()

    local curLevelName = self._curLevelName
    local adapter = self._targetAdapter
    local scene = self._targetSceneScene

    self._targetAdapter = nil
    self._targetSceneScene = nil
    self._loadType = 0

    self._isLoading = false

    adapter:OnEnterLevel(scene, self._loadSceneMode)

    FireEvent(EventNames.LOADING_FINISHED, 1)

    --FireEvent(EventNames.LOADER_FINISHED)
    --FireEvent(EventNames.LEVEL_LOAD_OK, curLevelName)
    --FireEvent(EventNames.ON_MAP_CREATED, curLevelName)

    LGameRunMode.ClearRunMode()
    FireEvent(EventNames.LOADING_END)

    if gLGameScene then
        if self:IsCheckRemainScene() then
            gLGameScene:CheckChangeRemainScene()
        else
            gLGameScene:SetChangeSceneRemainParams()
        end
    end
end

function LxLoaderAdapter:OnTargetLevelLoaded(scene, loadSceneMode)
    if loadSceneMode == LoadSceneMode.Single then
        self:OnSingleLevelLoaded(scene)
    end
end

function LxLoaderAdapter:OnSingleLevelLoaded(scene)
    local name = scene.name
    if self._targetLevelName ~= name then
        if LOG_INFO_ENABLED then
            printError("LevelMgr", "--->>>not this level, loaded \"%s\", want is \"%s\"" , name, self._targetLevelName)
        end
        return
    end

    self._targetSceneScene = scene

    self._targetAdapter:OnLevelLoaded()

    local param = self._targetAdapter:GetParam() or {}

    local isLoadMap = false
    if not string.isempty(param.mapName) then
        self._loadMapName = param.mapName
        isLoadMap = true
    end

    local batchTask = self:GetBatchTask()
    batchTask:InitBatchTask(self.OnBatchTaskText, self.OnBatchTaskProgress, self.OnLoadAfterTaskOk, self)

    if isLoadMap then
        batchTask:AddBatchTask("loadMap", "", self.DoInternalLoadMap, self)
    end

    if self._loadType == ELoadType.NoLoader then
        batchTask:AddBatchTask("clearOpenPanel", "", self.ClearOpenPanel, self)
        batchTask:AddBatchTask("unload_gc", "", self.DoGameUnloadWithGC, self)
    end

    self._targetAdapter:AfterLevelLoaded(batchTask)

    batchTask:StartBatchTask()
end

function LxLoaderAdapter:DoInternalLoadMap(actionOk, actionObj)
    local adapter = self._targetAdapter
    local requester = MgrCenter.MapMgr:LoadMap(self._targetSceneScene, self._loadMapName, function(gameObj)
        adapter:SetMapGo(gameObj)
        actionOk(actionObj)
    end)
    adapter:SetMapResRequester(self._loadMapName, requester)
    requester:StartRequester()
end
