function LxLoaderAdapter:OnLoadBeforeTaskOk()
    self._progress = LOAD_MAX_PROGRESS
    FireEvent(EventNames.LOADING_FINISHED, self._progress)
    self:StartFrameTimer("wait_loaded", 1,false,-1,function()
        local progress = self._progress
        if progress < 1 then
            progress = progress + 0.02
            if progress > 1 then
                progress = 1
            end
            self._progress = progress
            FireEvent(EventNames.LOADING_PROGRESS, self._progress)
            --FireEvent(EventNames.LOADER_PROGRESS, self._progress)
        end
    end)
end

function LxLoaderAdapter:OnLoadAfterTaskOk()
    self:InternalFinishLoad()
end

