---等待的时间比较短的清理资源
function LxLoaderAdapter:DoGameUnloadWithGC(actionOk, actionObj)
    local unusedCount, total = LxResUtil.CalcUnusedAssetProxys()
    if LOG_INFO_ENABLED then
        printInfo("LoaderAdapter", string.format("当前可释放proxy数量：%s， 总数量：%s", tostring(unusedCount), tostring(total)))
    end

    local isExecuteGC = false

    --使用适当的判断条件，减少调用unload的次数，降低游戏内切换场景的发热量
    if unusedCount > LGameSettings.clearBundleCount or total > LGameSettings.clearBundleTotalCount then
        --增加清理时间间隔
        local curTime = Time.realtimeSinceStartup
        local nextTime = self._nextFreeGCTime
        if not nextTime or nextTime <= curTime then
            isExecuteGC = true
            self._nextFreeGCTime = curTime + 120
        end
    end

    if isExecuteGC then
        if LOG_INFO_ENABLED then
            printInfo("LoaderAdapter", "满足清理资源条件，清理资源。")
        end
        LxResUtil.ClearUnusedAssets()
        PJXGameMgr:GameUnloadWithGC(function()
            actionOk(actionObj)
        end)
    else
        if LOG_INFO_ENABLED then
            printInfo("LoaderAdapter", "未达到清理资源条件，不清理清理资源。")
        end
        actionOk(actionObj)
    end
end

function LxLoaderAdapter:LoadLevel(actionOk, actionObj)
