function LxLoaderAdapter:PreloadAssets(actionOk, actionObj)
    local dataList = self:GetPreLoadAssetList(self._targetLevelName)
    if not dataList or #dataList == 0 then
        actionOk(actionObj)
        return
    end
    local ctrl = self._preloadTask
    if not ctrl then
        ctrl = require("LApp.component.task.LxPreloadTask"):New()
        ctrl:Initialize()
        self._preloadTask = ctrl
    end
    ctrl:InitPreload(function()
        --FireEvent(EventNames.LOADER_PROGRESS, LOAD_MAX_PROGRESS_STEP1)
        FireEvent(EventNames.LOADING_PROGRESS, LOAD_MAX_PROGRESS_STEP1)
        actionOk(actionObj)
    end, function(loadCount, totalCount)
        --FireEvent(EventNames.LOADER_PROGRESS, (loadCount * LOAD_MAX_PROGRESS_STEP1 ) / totalCount)
        FireEvent(EventNames.LOADING_PROGRESS, (loadCount * LOAD_MAX_PROGRESS_STEP1 ) / totalCount)
    end)

    for _k,v in ipairs(dataList) do
        ctrl:AddLoadData(v.assetPath, v.assetType, v.loadType)
    end
    ctrl:StartPreload()
end
