function LxLoaderAdapter:PreloadAssets2(actionOk, actionObj)
    if self._targetLevelName == LevelNames.Login then
        if LGameSettings.isLoginAfter then
            actionOk(actionObj)
            return
        end
        gLxMain:GetPreloadRes():EnterLoginPreload(function()
            --FireEvent(EventNames.LOADER_PROGRESS, LOAD_MAX_PROGRESS_STEP1 + LOAD_MAX_PROGRESS_STEP2)
            FireEvent(EventNames.LOADING_PROGRESS, LOAD_MAX_PROGRESS_STEP1 + LOAD_MAX_PROGRESS_STEP2)
            actionOk(actionObj)
        end, function(loadCount, totalCount)
            --FireEvent(EventNames.LOADER_PROGRESS, LOAD_MAX_PROGRESS_STEP1 + (loadCount * LOAD_MAX_PROGRESS_STEP2)   / totalCount)
            FireEvent(EventNames.LOADING_PROGRESS, LOAD_MAX_PROGRESS_STEP1 + (loadCount * LOAD_MAX_PROGRESS_STEP2)   / totalCount)
        end)
    elseif self._targetLevelName == LevelNames.Main then
        gLxMain:GetPreloadRes():EnterGamePreload(function()
            actionOk(actionObj)
        end, function(loadCount, totalCount)
            --FireEvent(EventNames.LOADER_PROGRESS, LOAD_MAX_PROGRESS_STEP1 + (loadCount * LOAD_MAX_PROGRESS_STEP2)   / totalCount)
            FireEvent(EventNames.LOADING_PROGRESS, LOAD_MAX_PROGRESS_STEP1 + (loadCount * LOAD_MAX_PROGRESS_STEP2)   / totalCount)
        end)
    else
        if LOG_INFO_ENABLED then
            printInfo("LoaderAdapter", "---->>> PreLoad2 skip ...")
        end
        actionOk(actionObj)
    end
end



return LxLoaderAdapter